    obs, reward, terminated, truncated, info = env.step(action)
    print(f"Reward: {reward:.4f}")
    print(f"Info: {info}")
    
    # Test flat mode
    print("\nTesting flat mode...")
    env_flat = make_single_agent_env("reactive_uniform", flat=True)
    obs_flat, _ = env_flat.reset()
    print(f"Flat observation shape: {obs_flat.shape if isinstance(obs_flat, np.ndarray) else 'N/A'}")
    print(f"Flat action space: {env_flat.action_space}")
    
    action = env_flat.action_space.sample()
    obs_flat, reward, _, _, info = env_flat.step(action)
    print(f"Reward: {reward:.4f}")
    
    print("\nAll tests passed!")
